                        var DeviceDatetime = moment(moment.utc(new Date(obj.Date * 1000)).toDate()).format('DD-MM-YYYY hh:mm:ss a');
                        $scope.model.CurrentDate = DeviceDatetime;
                        $scope.model.CurrentSpeed = parseFloat(obj.Speed).toFixed(2);
