                    // result = '<span style="font-size: 20px;color: green" ng-click="UpdateStatus(' + data.id + ',false,' + dateFlag + ')"> &#x2714;</span>';
                    result = '<span style="font-size: 20px;color: green"> &#x2714;</span>';
