        $scope.UpdateStatus = function (id, IsActive, dateFlag) {
            var message = '';
            if (IsActive == true) {
                IsActive = 1;
                message = 'Are you sure to Activate this SIM ?';
            } else {
                IsActive = 0;
                message = 'Are you sure to DeActivate this SIM ?';
            }

            var confirm = $mdDialog.confirm()
                .title(message)
                .ok('Ok')
                .cancel('Cancel')
            $mdDialog.show(confirm).then(function () {

                var params = {
                    IsActive: IsActive,
                    id: id,
                    flg: false,
                    dateFlag: dateFlag,
                }
                if (IsActive == 1) {
                    if (dateFlag == false) {
                        var confirm = $mdDialog.confirm()
                            .title('You want to Update Expiry Date?')
                            .ok('YES')
                            .cancel('NO')
                        $mdDialog.show(confirm).then(function () {
                            var params = {
                                IsActive: IsActive,
                                id: id,
                                flg: true,
                            }
                            updateIsActiveStatus(params)
                        }, function () {
                            updateIsActiveStatus(params);
                        });
                    } else {
                        updateIsActiveStatus(params);
                    }
                } else {
                    updateIsActiveStatus(params);
                }

            });


        }

        function updateIsActiveStatus(params) {
            $http.get($rootScope.RoutePath + "PetDevice/UpdateStatus", { params: params }).then(function (data) {
                $mdToast.show(
                    $mdToast.simple()
                        .textContent(data.data.message)
                        .position('top right')
                        .hideDelay(3000)
                );
                // $scope.resetForm();
                // $scope.init();
                GetPetDevice(true);
            });
        }

