                "&IdUser=" + $scope.modelSearch.IdUser + "&DeviceId=" + $scope.modelSearch.DeviceId + "&TimeZone=" + $rootScope.CurrentTimeZone + "&IsAdmin=" + IsAdmin + "&IsSalesAgent=" + IsSalesAgent;
