(function() {
    'use strict';

    angular
        .module('app.Forgotpassword')
        .controller('ForgotpasswordController', ForgotpasswordController);

    /** @ngInject */
    function ForgotpasswordController($scope, $state, $rootScope, $http, $cookieStore, $mdDialog, $document, $mdToast, $timeout) {
        $rootScope.appId = localStorage.getItem('appId');
        $('.logo').css('background-image', 'url(' + localStorage.getItem('Logo') + ')');
        $scope.init = function() {
            $scope.model = {
                email: '',
                idApp: $rootScope.appId,
            }
        }

        $scope.ResetPassword = function() {
            var Email = $scope.model.email;
            $http.get($rootScope.RoutePath + "account/forgotpasswordNew?email=" + Email.toLowerCase() + "&idApp=" + $rootScope.appId + "&AppName=" + localStorage.getItem('appName')).then(function(response) {
                console.log(response);
                if (response.data.success == true) {
                    $mdToast.show(
                        $mdToast.simple()
                        .textContent(response.data.message)
                        .position('top right')
                        .hideDelay(3000)
                    );
                    $scope.email = '';
                    $timeout(function() {
                        $state.go('app.login', {
                            cache: false
                        });
                    }, 1500);

                } else {
                    if (response.data.data == 'TOKEN') {
                        $cookieStore.remove('UserName');
                        $cookieStore.remove('token');
                        $state.go('app.login', {
                            cache: false
                        });
                    } else {
                        $mdToast.show(
                            $mdToast.simple()
                            .textContent(response.data.message)
                            .position('top right')
                            .hideDelay(3000)
                        );
                    }
                }
            });
        }

        $scope.init();
    }
})();
