                    $scope.data = [$scope.lstDashBoardInfo.sumTodayProcessing, $scope.lstDashBoardInfo.sumTodayPending, $scope.lstDashBoardInfo.sumTodayCancelled, $scope.lstDashBoardInfo.sumTodayCompleted];
